        union(x: number, y: number): boolean {
            const rootX = this.find(x);
            const rootY = this.find(y);
            if (rootX === rootY) return false;
            if (this.rank[rootX] < this.rank[rootY]) {
                this.parent[rootX] = rootY;
            } else {
                this.parent[rootY] = rootX;
                if (this.rank[rootX] === this.rank[rootY]) {
                    this.rank[rootX]++;
                }
            }
            return true;
        }
    }

    // Build DSU
    const dsu = new DSU(c + 1); // stations are 1-based
    for (const [u, v] of connections) {
        dsu.union(u, v);
    }

    // Group stations by root
    const componentHeaps: Map<number, MinHeap> = new Map();
    for (let i = 1; i <= c; i++) {
        const root = dsu.find(i);
        if (!componentHeaps.has(root)) {
            componentHeaps.set(root, new MinHeap());
