        componentHeaps.get(root)!.push(i);
    }

    // Track online status
    const online: boolean[] = new Array(c + 1).fill(true);

    // Process queries
    const result: number[] = [];
    for (const [type, x] of queries) {
        if (type === 1) {
            if (online[x]) {
                result.push(x);
            } else {
                const root = dsu.find(x);
                const heap = componentHeaps.get(root)!;
