```rust
use std::collections::{HashMap, BinaryHeap};

struct DSU {
    parent: Vec<usize>,
    rank: Vec<usize>,
}

impl DSU {
    fn new(n: usize) -> Self {
        let parent = vec![0; n + 1];
        for i in 1..=n {
            parent[i] = i;
        }
        let rank = vec![1; n + 1];
        DSU { parent, rank }
    }

    fn find(&mut self, x: usize) -> usize {
        if self.parent[x] != x {
            self.parent[x] = self.find(self.parent[x]);
        }
        self.parent[x]
    }

    fn union(&mut self, x: usize, y: usize) {
        let x_root = self.find(x);
        let y_root = self.find(y);
        if x_root == y_root {
            return;
        }
        if self.rank[x_root] < self.rank[y_root] {
            self.parent[x_root] = y_root;
        } else {
            self.parent[y_root] = x_root;
            if self.rank[x_root] == self.rank[y_root] {
                self.rank[x_root] += 1;
            }
        }
    }
}

fn solve(c: i64, connections: Vec<Vec<i64>>, queries: Vec<Vec<i64>>) -> Vec<i64> {
    let c = c as usize;
    let mut dsu = DSU::new(c);
    for connection in &connections {
        let u = connection[0] as usize;
        let v = connection[1] as usize;
        dsu.union(u, v);
    }

    let mut component_map = HashMap::new();
    for i in 1..=c {
        let root = dsu.find(i);
        component_map.entry(root).or_insert_with(Vec::new).push(i);
    }

    let mut component_heaps = HashMap::new();
    for (root, stations) in component_map {
        let mut heap = BinaryHeap::new();
        for &station in stations.iter() {
            heap.push(station);
        }
        component_heaps.insert(root, heap);
    }

    let mut online = vec![true; c + 1];
    let mut result = Vec::new();

    for query in queries {
        let t = query[0];
        let x = query[1] as usize;

        if t == 1 {
            if online[x] {
                result.push(x as i64);
            } else {
                let root = dsu.find(x);
                let heap = component_heaps.get_mut(&root).unwrap();
                loop {
                    if heap.is_empty() {
                        result.push(-1);
                        break;
                    }
                    let top = heap.peek().unwrap();
                    if online[*top] {
                        result.push(*top as i64);
                        break;
                    } else {
                        heap.pop();
                    }
                }
            }
        } else {
            online[x] = false;
        }
    }

    result
}
```

