                    if (online[currentTop]) {
                        result.push(currentTop);
                        break;
                    } else {
                        heap.pop();
                        currentTop = heap.peek();
                    }
                }
                if (heap.isEmpty()) {
                    result.push(-1);
                }
            }
        } else {
            // type 2: offline
            online[x] = false;
        }
    }

    return result;
}

