A min-heap can be implemented as an array, with the heap property maintained. The heap is a binary tree where each parent is smaller than its children. The smallest element is at the root.

The standard operations are:

- push: add an element to the heap, maintaining the heap property.

- pop: remove the smallest element.

- peek: get the smallest element.

So, for each component, we can create a heap. For example:

class MinHeap {
    private heap: number[];
    constructor() {
        this.heap = [];
    }
    push(value: number): void {
        this.heap.push(value);
        this.heapifyUp(this.heap.length - 1);
    }
    pop(): number {
        if (this.heap.length === 0) return -1;
        const val = this.heap[0];
        this.heap[0] = this.heap.pop()!;
        this.heapifyDown(0);
        return val;
    }
    peek(): number {
        return this.heap[0];
    }
    private heapifyUp(index: number): void {
        while (index > 0) {
            const parentIndex = Math.floor((index - 1) / 2);
            if (this.heap[parentIndex] <= this.heap[index]) break;
            [this.heap[index], this.heap[parentIndex]] = [this.heap[parentIndex], this.heap[index]];
            index = parentIndex;
        }
    }
    private heapifyDown(index: number): void {
        const n = this.heap.length;
        while (index < n) {
            const left = 2 * index + 1;
            const right = 2 * index + 2;
            let smallest = index;
            if (left < n && this.heap[left] < this.heap[smallest]) smallest = left;
            if (right < n && this.heap[right] < this.heap[smallest]) smallest = right;
            if (smallest === index) break;
            [this.heap[index], this.heap[smallest]] = [this.heap[smallest], this.heap[index]];
            index = smallest;
        }
    }
}

